import{_ as t,c as o,o as a,ag as i}from"./chunks/framework.DD2hp6gW.js";const p=JSON.parse('{"title":"Dropdown Select Field","description":"","frontmatter":{},"headers":[],"relativePath":"fields/select.md","filePath":"fields/select.md","lastUpdated":null}'),l={name:"fields/select.md"};function n(s,e,r,d,c,h){return a(),o("div",null,e[0]||(e[0]=[i('<h1 id="dropdown-select-field" tabindex="-1">Dropdown Select Field <a class="header-anchor" href="#dropdown-select-field" aria-label="Permalink to &quot;Dropdown Select Field&quot;">​</a></h1><p>The <strong>Select</strong> field presents a classic dropdown menu where customers must choose exactly one option from a list. It&#39;s ideal when you have many choices but want to keep the interface clean and compact.</p><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li>Selecting a size (Small, Medium, Large, X-Large)</li><li>Choosing a material or finish (Wood, Metal, Plastic)</li><li>Picking a delivery date or time slot</li><li>Selecting a configuration or variant</li></ul><h2 id="field-settings" tabindex="-1">Field Settings <a class="header-anchor" href="#field-settings" aria-label="Permalink to &quot;Field Settings&quot;">​</a></h2><p>When you add a Select field and expand it in the builder, the following settings are available:</p><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The title displayed above the dropdown (e.g., &quot;Choose Your Size&quot;).</td></tr><tr><td style="text-align:left;"><strong>Description</strong></td><td style="text-align:left;">Optional help text shown below the dropdown.</td></tr><tr><td style="text-align:left;"><strong>Required</strong></td><td style="text-align:left;">When checked, the customer must select an option before adding the product to the cart.</td></tr></tbody></table><h3 id="choices-options" tabindex="-1">Choices (Options) <a class="header-anchor" href="#choices-options" aria-label="Permalink to &quot;Choices (Options)&quot;">​</a></h3><p>The core of the Select field is its <strong>Choices</strong> table. You must define at least one choice. Each choice has the following columns:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Column</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The text the customer sees in the dropdown menu (e.g., &quot;Large&quot;). The <strong>Value</strong> is automatically generated from the label as a lowercase, underscore-separated string (e.g., <code>large</code>).</td></tr><tr><td style="text-align:left;"><strong>Price</strong></td><td style="text-align:left;">The numeric amount to add to the product price when this specific choice is selected. Only visible when Price Type is not &quot;No Price&quot;.</td></tr><tr><td style="text-align:left;"><strong>Price Type</strong></td><td style="text-align:left;">How this choice affects pricing. Options: <strong>No Price</strong>, <strong>Flat Fee</strong>, <strong>Percentage of Base</strong>, or <strong>Formula</strong>. Each choice can have its own independent price type.</td></tr><tr><td style="text-align:left;"><strong>Weight</strong></td><td style="text-align:left;">Additional shipping weight to add when this choice is selected (affects shipping calculations).</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The <strong>Per Character</strong> price type is not available for individual choices since select options are predefined values, not freeform text.</p></div><p>You can add new choices using the <strong>+ Add Choice</strong> button and remove them using the trash icon on each row.</p><h2 id="conditional-logic" tabindex="-1">Conditional Logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional Logic&quot;">​</a></h2><p>You can show or hide this field based on the value of another field in the same group. For example, show a &quot;Sleeve Length&quot; dropdown only when the customer selects &quot;Long Sleeve&quot; from another radio button field.</p><p>For full details on setting up rules, see the <a href="./../conditional-logic.html">Conditional Logic</a> page.</p>',16)]))}const u=t(l,[["render",n]]);export{p as __pageData,u as default};
